class Solution:
    def isPossible(self, nums: List[int]) -> bool:
        count = {}
        for num in nums:
            if num - 1 in count:
                count[num - 1] -= 1
                if count[num - 1] == 0:
                    del count[num - 1]
                count[num] = count.get(num, 0) + 1
            else:
                count[num] = count.get(num, 0) + 1
        for k, v in count.items():
            if v < 3:
                return False
        return True
